const SCREENSHOT_FONT = "GScreenshot";

const DATA_URI =
  "data:font/woff2;base64,";

let loaded: Promise<void> | undefined;

export function loadScreenshotFont(): Promise<void> {
  if (loaded === undefined) {
    const style = document.createElement("style");
    style.textContent =
      `@font-face{font-family:${SCREENSHOT_FONT};font-weight:400;font-style:normal;` +
      `src:url(${DATA_URI}) format("woff2")}` +
      `body{font-family:${SCREENSHOT_FONT}}`;
    document.head.appendChild(style);
    loaded = document.fonts
      .load(`13px ${SCREENSHOT_FONT}`)
      .then(() => document.fonts.ready)
      .then(() => undefined);
  }
  return loaded;
}
